import React from 'react';
import { Eye, Search, Calendar, User, IndianRupee, Trash2 } from 'lucide-react';

const SavedBills = ({ invoices, onView }) => {
  return (
    <div className="max-w-6xl mx-auto">
      <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-4">
        <h2 className="text-4xl font-bold gold-text-gradient">Billing Records</h2>
        <div className="relative w-full md:w-72">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
          <input
            type="text"
            placeholder="Search records..."
            className="w-full bg-surface border border-gray-700 rounded-full py-2 pl-10 pr-4 focus:border-yellow-500 outline-none transition"
          />
        </div>
      </div>

      {invoices.length === 0 ? (
        <div className="text-center py-20 glass rounded-3xl">
          <Calendar className="mx-auto text-gray-600 mb-4" size={48} />
          <h3 className="text-xl font-medium text-gray-400">No invoices found yet.</h3>
          <p className="text-gray-500 mt-2">Create your first bill to see it here!</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {invoices.map((invoice) => (
            <div
              key={invoice.id}
              className="glass p-6 rounded-2xl hover:border-yellow-500/30 transition-all group cursor-pointer"
              onClick={() => onView(invoice)}
            >
              <div className="flex justify-between items-start mb-4">
                <span className="bg-yellow-500/10 text-yellow-500 text-xs font-bold px-2 py-1 rounded">
                  {invoice.id}
                </span>
                <span className="text-gray-500 text-sm flex items-center gap-1">
                  <Calendar size={14} /> {invoice.date}
                </span>
              </div>

              <h3 className="text-xl font-bold mb-1 flex items-center gap-2">
                <User size={18} className="text-yellow-500" /> {invoice.customerName}
              </h3>
              <p className="text-gray-400 text-sm mb-6">{invoice.customerPhone}</p>

              <div className="flex justify-between items-center pt-4 border-t border-gray-800">
                <div>
                  <p className="text-xs text-gray-500 uppercase">Total Amount</p>
                  <p className="text-xl font-bold text-yellow-500 flex items-center">
                    <IndianRupee size={16} /> {invoice.finalTotal}
                  </p>
                </div>
                <button className="bg-yellow-500/10 p-3 rounded-xl text-yellow-500 group-hover:bg-yellow-500 group-hover:text-black transition-all">
                  <Eye size={20} />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default SavedBills;
